# Optimized code: truncates terms to prevent exponential memory growth.
# Safe because a(n) depends only on the prefix of the (n-1)-th term.
def get_next_look_and_say_truncated(s, max_len):
    result, i, chars_generated = [], 0, 0
    while i < len(s) and chars_generated < max_len:
        count = 1
        while i + 1 < len(s) and s[i] == s[i+1]: i += 1; count += 1
        chunk = f"{count}{s[i]}"
        result.append(chunk); chars_generated += len(chunk); i += 1
    return "".join(result)[:max_len]
def a(n):
    current_term = "1"
    for i in range(1, n + 1):
        if i == n: return int(current_term[n-1]) if len(current_term) >= n else 0
        current_term = get_next_look_and_say_truncated(current_term, n * 2)

